-      return V.getInt();
-  }
-  Values.emplace_back(L, LoopVariant);
-  LoopDisposition D = computeLoopDisposition(S, L);
-  auto &Values2 = LoopDispositions[S];
-  for (auto &V : llvm::reverse(Values2)) {
