-
-  if (ClassifyExpressions) {
-    OS << "Classifying expressions for: ";
-    F.printAsOperand(OS, /*PrintType=*/false);
-    OS << "\n";
-    for (Instruction &I : instructions(F))
-      if (isSCEVable(I.getType()) && !isa<CmpInst>(I)) {
-        OS << I << '\n';
